(() => {
  "use strict";

  const originalFetch = typeof self.fetch === "function" ? self.fetch.bind(self) : null;
  const embeddedEngBase64 = "";
  let cachedEngBytes = null;

  function decodeBase64(base64) {
    const binary = self.atob(base64);
    const bytes = new Uint8Array(binary.length);

    for (let index = 0; index < binary.length; index += 1) {
      bytes[index] = binary.charCodeAt(index);
    }

    return bytes;
  }

  function getEmbeddedEngBytes() {
    if (!cachedEngBytes) {
      cachedEngBytes = decodeBase64(embeddedEngBase64);
    }

    return cachedEngBytes;
  }

  function isBundledEngRequest(input) {
    const url = typeof input === "string"
      ? input
      : input && typeof input.url === "string"
        ? input.url
        : "";

    return /(^|[\/])eng\.traineddata(?:\.gz)?(?:[?#].*)?$/i.test(url);
  }

  self.fetch = async (input, init) => {
    if (isBundledEngRequest(input)) {
      const bytes = getEmbeddedEngBytes();
      const copy = bytes.slice();

      return {
        ok: true,
        status: 200,
        arrayBuffer: async () => copy.buffer,
      };
    }

    if (!originalFetch) {
      throw new Error("Fetch is unavailable in the OCR worker.");
    }

    return originalFetch(input, init);
  };
})();

